def solve():
    import sys
    a, b, c = map(int, sys.stdin.readline().split())
    # 세 수가 모두 서로 달라야 카도마츠 수열이 될 수 있다.
    if a == b or b == c or a == c:
        print("No")
        return
    # 가운데 값 b가 세 수 중 최댓값이거나 최솟값이면 카도마츠 수열이다.
    if b == max(a, b, c) or b == min(a, b, c):
        print("Yes")
    else:
        print("No")

solve()
